import{c as t,Q as r,j as a,m as o}from"./chunks/framework.rlpw0eGz.js";const p=JSON.parse('{"title":"Memoh 中文文档","description":"","frontmatter":{},"headers":[],"relativePath":"zh/index.md","filePath":"zh/index.md","lastUpdated":1778736656000}'),s={name:"zh/index.md"};function i(l,e,n,h,m,d){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="memoh-中文文档" tabindex="-1">Memoh 中文文档 <a class="header-anchor" href="#memoh-中文文档" aria-label="Permalink to &quot;Memoh 中文文档&quot;">​</a></h1><p>Memoh（读作 /ˈmemoʊ/）是面向多成员、结构化长期记忆和独立 workspace 的 AI 智能体平台。你可以创建多个机器人，为每个机器人准备工作区与长期记忆，并通过 Telegram、Discord、飞书、QQ、Matrix、Misskey、钉钉、企微、微信、公众号、邮件或内置网页端接入。</p><p>Memoh 有两种分发方式：</p><ul><li><strong>Desktop 桌面版</strong>：适合个人和本地使用，原生 App 会启动自己的本地 server、embedded Qdrant、本地存储和 bundled CLI。</li><li><strong>Server Deploy</strong>：适合长期在线、多人、多租户或需要持续接入外部渠道的部署。</li></ul><h2 id="起步" tabindex="-1">起步 <a class="header-anchor" href="#起步" aria-label="Permalink to &quot;起步&quot;">​</a></h2><ul><li><strong><a href="/zh/installation/">安装选择</a></strong>：先判断用 Desktop 还是 Server Deploy。</li><li><strong><a href="/zh/installation/desktop.html">Desktop 桌面版</a></strong>：安装本地原生客户端。</li><li><strong><a href="/zh/installation/docker.html">Server Deploy</a></strong>：用 Docker Compose 部署 Memoh server。</li><li><strong><a href="/zh/getting-started/provider-and-model.html">供应商与模型</a></strong>：配置上游 API、模型类型与能力标记。</li><li><strong><a href="/zh/getting-started/bot.html">机器人</a></strong>：创建机器人并配置各标签页。</li><li><strong><a href="/zh/getting-started/sessions.html">会话</a></strong>：聊天与 Discuss 模式、状态区、路由。</li></ul><h2 id="功能指南" tabindex="-1">功能指南 <a class="header-anchor" href="#功能指南" aria-label="Permalink to &quot;功能指南&quot;">​</a></h2><ul><li><strong><a href="/zh/installation/workspace-backends.html">Workspace backend</a></strong>：选择容器和本地 workspace runtime。</li><li><strong><a href="/zh/getting-started/browser-computer-use.html">Browser / Computer Use</a></strong>：操作有头浏览器和图形桌面。</li><li><strong><a href="/zh/getting-started/files.html">文件</a></strong>：浏览和编辑机器人 workspace 文件系统。</li><li><strong><a href="/zh/channels/index.html">渠道总览</a></strong>：支持的平台与各平台分篇。</li><li><strong><a href="/zh/getting-started/access.html">访问控制</a></strong>：ACL 预设、规则顺序与按来源限定。</li><li><strong><a href="/zh/getting-started/skills.html">技能</a></strong>：托管/发现、生效/被遮蔽、从超市安装。</li><li><strong><a href="/zh/getting-started/supermarket.html">超市</a></strong>：技能与 MCP 模板安装。</li><li><strong><a href="/zh/getting-started/mcp.html">MCP</a></strong>：Stdio/远程、OAuth、探测与导入导出。</li><li><strong><a href="/zh/getting-started/memory.html">长期记忆</a></strong>：记忆提供方与在界面里的操作。</li><li><strong><a href="/zh/getting-started/compaction.html">会话上下文压缩</a></strong>：缩小当前会话占用，不动存储里的长期记忆。</li><li><strong><a href="/zh/getting-started/slash-commands.html">斜杠命令</a></strong>：命令结构、权限与速查表。</li></ul><h2 id="记忆与语音提供方" tabindex="-1">记忆与语音提供方 <a class="header-anchor" href="#记忆与语音提供方" aria-label="Permalink to &quot;记忆与语音提供方&quot;">​</a></h2><ul><li><a href="/zh/memory-providers/index.html">记忆提供方总览</a> · <a href="/zh/memory-providers/builtin.html">内置</a> · <a href="/zh/memory-providers/mem0.html">Mem0</a> · <a href="/zh/memory-providers/openviking.html">OpenViking</a></li><li><a href="/zh/tts-providers/index.html">TTS 总览</a> · <a href="/zh/tts-providers/edge.html">Edge TTS</a></li></ul>',10)])])}const c=t(s,[["render",i]]);export{p as __pageData,c as default};
